import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import { Button } from '../components/ui/button';
import { Input } from '../components/ui/input';
import { toast } from 'sonner';
import { ArrowLeft, Search } from 'lucide-react';

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;
const API = `${BACKEND_URL}/api`;

const MUSCLE_GROUPS = ['All', 'Chest', 'Back', 'Shoulders', 'Legs', 'Biceps', 'Triceps', 'Core'];

export default function ExercisesPage() {
  const navigate = useNavigate();
  const { getAuthHeader } = useAuth();
  const [exercises, setExercises] = useState([]);
  const [filteredExercises, setFilteredExercises] = useState([]);
  const [selectedMuscleGroup, setSelectedMuscleGroup] = useState('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchExercises();
  }, []);

  useEffect(() => {
    filterExercises();
  }, [exercises, selectedMuscleGroup, searchQuery]);

  const fetchExercises = async () => {
    try {
      const response = await axios.get(`${API}/exercises`, {
        headers: getAuthHeader()
      });
      setExercises(response.data);
    } catch (error) {
      toast.error('Failed to load exercises');
    } finally {
      setLoading(false);
    }
  };

  const filterExercises = () => {
    let filtered = exercises;

    if (selectedMuscleGroup !== 'All') {
      filtered = filtered.filter(ex => ex.muscle_group === selectedMuscleGroup);
    }

    if (searchQuery) {
      filtered = filtered.filter(ex =>
        ex.name.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    setFilteredExercises(filtered);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0A0A0A] flex items-center justify-center">
        <div className="text-white text-lg">Loading...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0A0A0A]">
      {/* Header */}
      <header className="bg-[#141414] border-b border-[#27272A]/40 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center gap-4 mb-4">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => navigate('/')}
              className="text-[#A1A1AA] hover:text-white hover:bg-[#1A1A1A]"
              data-testid="back-button"
            >
              <ArrowLeft className="w-5 h-5" />
            </Button>
            <h1 className="barlow text-2xl font-black tracking-tighter text-white" data-testid="page-title">
              Exercise Library
            </h1>
          </div>

          {/* Search */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-[#71717A]" />
            <Input
              type="text"
              placeholder="Search exercises..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 bg-[#0A0A0A] border-[#27272A] text-white focus:border-[#007AFF] focus:ring-2 focus:ring-[#007AFF]"
              data-testid="search-input"
            />
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        {/* Muscle Group Filter */}
        <div className="mb-6 overflow-x-auto">
          <div className="flex gap-2 pb-2">
            {MUSCLE_GROUPS.map((group) => (
              <button
                key={group}
                onClick={() => setSelectedMuscleGroup(group)}
                className={`px-4 py-2 rounded-md text-sm font-bold uppercase tracking-widest whitespace-nowrap transition-colors ${
                  selectedMuscleGroup === group
                    ? 'bg-[#007AFF] text-white'
                    : 'bg-[#1A1A1A] text-[#A1A1AA] border border-[#27272A] hover:border-[#007AFF]'
                }`}
                data-testid={`filter-${group.toLowerCase()}`}
              >
                {group}
              </button>
            ))}
          </div>
        </div>

        {/* Exercise Grid */}
        {filteredExercises.length === 0 ? (
          <div className="text-center py-12">
            <p className="text-[#A1A1AA] text-lg">No exercises found</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredExercises.map((exercise) => (
              <div
                key={exercise.id}
                className="bg-[#1A1A1A] border border-[#27272A] rounded-md overflow-hidden hover:border-[#007AFF] transition-colors"
                data-testid={`exercise-card-${exercise.id}`}
              >
                <div className="h-48 overflow-hidden">
                  <img
                    src={exercise.image_url}
                    alt={exercise.name}
                    className="w-full h-full object-cover"
                  />
                </div>
                <div className="p-4">
                  <h3 className="barlow text-lg font-bold tracking-tight text-white mb-1">
                    {exercise.name}
                  </h3>
                  <p className="text-[#A1A1AA] text-sm uppercase tracking-widest mb-2">
                    {exercise.muscle_group}
                  </p>
                  <p className="text-[#71717A] text-sm mb-3">{exercise.description}</p>
                  <div className="flex items-center gap-3 text-[#71717A] text-xs uppercase tracking-widest">
                    <span>{exercise.default_sets} sets</span>
                    <span>×</span>
                    <span>{exercise.default_reps} reps</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}
